    var classifiableNames: Set<__String>;

    var unreachableFlow = createFlowNode(FlowFlags.Unreachable, /*node*/ undefined, /*antecedent*/ undefined);
    var bindBinaryExpressionFlow = createBindBinaryExpressionFlow();
