2751	    function bind(node: Node | undefined): void {
2752	        if (!node) {
2753	            return;
2754	        }
2755	        setParent(node, parent);
2756	        if (tracing) (node as TracingNode).tracingPath = file.path;
2757	        const saveInStrictMode = inStrictMode;
2758	
2759	        // Even though in the AST the jsdoc @typedef node belongs to the current node,
2760	        // its symbol might be in the same scope with the current node's symbol. Consider:
2761	        //
2762	        //     /** @typedef {string | number} MyType */
2763	        //     function foo();
2764	        //
2765	        // Here the current node is "foo", which is a container, but the scope of "MyType" should
2766	        // not be inside "foo". Therefore we always bind @typedef before bind the parent node,
2767	        // and skip binding this tag later when binding all the other jsdoc tags.
2768	
2769	        // First we bind declaration nodes to a symbol if possible. We'll both create a symbol
2770	        // and then potentially add the symbol to an appropriate symbol table. Possible
2771	        // destination symbol tables are:
2772	        //
2773	        //  1) The 'exports' table of the current container's symbol.
2774	        //  2) The 'members' table of the current container's symbol.
2775	        //  3) The 'locals' table of the current container.
2776	        //
2777	        // However, not all symbols will end up in any of these tables. 'Anonymous' symbols
2778	        // (like TypeLiterals for example) will not be put in any table.
2779	        bindWorker(node);
2780	        // Then we recurse into the children of the node to bind them as well. For certain
2781	        // symbols we do specialized work when we recurse. For example, we'll keep track of
2782	        // the current 'container' node when it changes. This helps us know which symbol table
2783	        // a local should go into for example. Since terminal nodes are known not to have
2784	        // children, as an optimization we don't process those.
2785	        if (node.kind > SyntaxKind.LastToken) {
2786	            const saveParent = parent;
2787	            parent = node;
2788	            const containerFlags = getContainerFlags(node);
2789	            if (containerFlags === ContainerFlags.None) {
2790	                bindChildren(node);
2791	            }
2792	            else {
2793	                bindContainer(node as HasContainerFlags, containerFlags);
2794	            }
2795	            parent = saveParent;
2796	        }
2797	        else {
2798	            const saveParent = parent;
2799	            if (node.kind === SyntaxKind.EndOfFileToken) parent = node;
