function bindEach(nodes: NodeArray<Node> | undefined, bindFunction: (node: Node) => void = bind): void {
    if (nodes === undefined) {
        return;
    }

    forEach(nodes, bindFunction);
}

function bindEachChild(node: Node) {
    forEachChild(node, bind, bindEach);
}

function bindChildren(node: Node): void {
    const saveInAssignmentPattern = inAssignmentPattern;
    // Most nodes aren't valid in an assignment pattern, so we clear the value here
    // and set it before we descend into nodes that could actually be part of an assignment pattern.
    inAssignmentPattern = false;

    // Clear Unreachable flag from previous binding (for incremental scenarios)
    if (isPotentiallyExecutableNode(node)) {
        (node as Mutable<Node>).flags &= ~NodeFlags.Unreachable;
    }

    if (currentFlow === unreachableFlow) {
        if (canHaveFlowNode(node)) {
            node.flowNode = undefined;
        }
        if (isPotentiallyExecutableNode(node)) {
            (node as Mutable<Node>).flags |= NodeFlags.Unreachable;
        }
        bindEachChild(node);
        bindJSDoc(node);
        inAssignmentPattern = saveInAssignmentPattern;
        return;
